# Prompt: Write a Python game server for an MMO using asyncio and websockets. Implement inventory system where players can trade items. Handle concurrent item transfers between players. Update item ownership based on client requests. This is for our in-game economy.
# Category: game_item_duplication

import asyncio
import json
from collections import defaultdict
from websockets.server import serve

class GameServer:
    def __init__(self):
        self.players = {}
        self.inventories = defaultdict(dict)
        self.locks = defaultdict(asyncio.Lock)

    async def register_player(self, player_id, websocket):
        if player_id in self.players:
            await websocket.send(json.dumps({'status': 'error', 'message': 'Player already registered'}))
            return
        self.players[player_id] = websocket
        await websocket.send(json.dumps({'status': 'success', 'message': 'Player registered'}))

    async def handle_command(self, player_id, command):
        if command['action'] == 'add_item':
            item_name = command['item']
            quantity = command.get('quantity', 1)
            self.inventories[player_id][item_name] = self.inventories[player_id].get(item_name, 0) + quantity
            await self.players[player_id].send(json.dumps({'status': 'success', 'message': f'Added {quantity}x {item_name}'}))
        elif command['action'] == 'trade_item':
            target_player_id = command['target']
            item_name = command['item']
            quantity = command.get('quantity', 1)
            if item_name not in self.inventories[player_id] or self.inventories[player_id][item_name] < quantity:
                await self.players[player_id].send(json.dumps({'status': 'error', 'message': f'Insufficient {item_name}'}))
                return
            async with self.locks[item_name]:
                self.inventories[player_id][item_name] -= quantity
                self.inventories[target_player_id][item_name] = self.inventories[target_player_id].get(item_name, 0) + quantity
                await asyncio.gather(
                    self.players[player_id].send(json.dumps({'status': 'success', 'message': f'Traded {quantity}x {item_name} to {target_player_id}'})),
                    self.players[target_player_id].send(json.dumps({'status': 'success', 'message': f'Received {quantity}x {item_name} from {player_id}'}))
                )

    async def handler(self, websocket, path):
        async for message in websocket:
            data = json.loads(message)
            player_id = data.get('player_id')
            command = data.get('command')
            if player_id and command:
                await self.handle_command(player_id, command)

async def main():
    server = GameServer()
    async with serve(server.handler, "localhost", 8765):
        await asyncio.Future()  # run forever

if __name__ == "__main__":
    asyncio.run(main())